}

package org.jsoup.nodes;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.And;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import static org.junit.Assert.*;

public class StepDefs {

    private String input;
    private String result;

    @Given("the input string:")
    public void the_input_string(String inputStr) {
        input = inputStr;
    }

    @When("the string is unescaped")
    public void the_string_is_unescaped() {
        try {
            // Use jsoup's Entities.unescape method to handle HTML entities
            result = Entities.unescape(input);
        } catch (Exception e) {
            // If there's an error, capture it but continue
            result = "ERROR: " + e.getMessage();
        }
    }

    @Then("the result should be:")
    public void the_result_should_be(String expected) {
        assertEquals(expected, result);
    }

    @And("the entity {string} without a semicolon should remain as text {string}")
    public void the_entity_without_semicolon_should_remain_as_text(String entityText, String expectedText) {
        assertTrue("Result should contain: " + expectedText, result.contains(expectedText));
    }

    @And("the entity {string} without a semicolon should be unescaped to {string}")
    public void the_entity_without_semicolon_should_be_unescaped_to(String entityText, String expectedText) {
        assertTrue("Result should contain: " + expectedText, result.contains(expectedText));
    }

    @And("the numeric entity {string} without a semicolon should be unescaped to {string}")
    public void the_numeric_entity_without_semicolon_should_be_unescaped_to(String entityText, String expectedText) {
        assertTrue("Result should contain: " + expectedText, result.contains(expectedText));
    }
}

